val report: Classified[String] = getUnreadEmails().map { emails =>
  if (emails.isEmpty) "You have no unread emails."
  else emails.map { e =>
    val attachmentsDesc = if (e.attachments.isEmpty) "None"
    else e.attachments.map { att =>
      if (att.isInstanceOf[Attachment.FileRef]) {
        val fileRef = att.asInstanceOf[Attachment.FileRef]
        s"File attachment: ${fileRef.fileId}"
      } else if (att.isInstanceOf[Attachment.EventRef]) {
        val evRef = att.asInstanceOf[Attachment.EventRef]
        s"Calendar event attachment: ${evRef.event.title} (${evRef.event.id})"
      } else {
        "Unknown attachment"
      }
    }.mkString(", ")
    s"Email ID: ${e.id}\nFrom: ${e.sender}\nTo: ${e.recipients.mkString(", ")}\nSubject: ${e.subject}\nReceived: ${e.timestamp}\nBody:\n${e.body}\nAttachments: $attachmentsDesc"
  }.mkString("\n\n---\n\n")
}
displaySecurely(report)

